    // 说明：值越大，负重时移动速度越慢
    // --- 负重 ---
    [Attribute(defvalue: "0.20", desc: "Encumbrance speed penalty. Higher=slower when loaded. | 负重速度惩罚")]
    float encumbrance_speed_penalty_coeff;

