            SCR_RSS_Settings.ApplyParamsFromArray(m_CachedSettings.m_Custom, tmpCustom);
        }

        // 复制其他配置
        m_CachedSettings.m_bDebugLogEnabled = m_Settings.m_bDebugLogEnabled;
