    // 计算太阳天顶角余弦（cos θ），输入纬度（deg）、年日、时刻（小时）
    protected float SolarCosZenith(float latDeg, int n, float localHour)
    {
        return SCR_EnvironmentAstronomyMath.SolarCosZenith(latDeg, n, localHour);
