// 负重缓存管理模块
// 负责管理负重的缓存计算和更新（事件驱动，性能优化）
// 模块化拆分：从 PlayerBase.c 提取的独立功能模块

class EncumbranceCache
{
    // 与 UpdateCache 内分段多项式一致，供服务器 RPC 等在缓存无效时复用
    static float ComputeSpeedPenaltyFromEffectiveWeight(float effectiveWeight)
    {
        float ratio = Math.Clamp(effectiveWeight / StaminaConstants.CHARACTER_WEIGHT, 0.0, 2.0);
        float rawPenalty = 0.0;
        if (ratio <= 0.3)
        {
            rawPenalty = 0.15 * ratio;
        }
        else if (ratio <= 0.6)
        {
            float segment = ratio - 0.3;
            rawPenalty = 0.045 + 0.35 * Math.Pow(segment, 1.5);
        }
        else
        {
            float segment = ratio - 0.6;
            rawPenalty = 0.25 + 0.65 * (segment * segment);
        }
        float coeff = StaminaConstants.GetEncumbranceSpeedPenaltyCoeff();
        rawPenalty = rawPenalty * (coeff / 0.20);
        float max_pen = StaminaConstants.GetEncumbranceSpeedPenaltyMax();
        return Math.Clamp(rawPenalty, 0.0, max_pen);
    }

    // ==================== 状态变量 ====================
    protected float m_fCachedCurrentWeight = 0.0; // 缓存的当前重量（kg）
    protected float m_fCachedEncumbranceSpeedPenalty = 0.0; // 缓存的速度惩罚
    protected float m_fCachedBodyMassPercent = 0.0; // 缓存的有效负重占体重百分比
    protected float m_fCachedEncumbranceStaminaDrainMultiplier = 1.0; // 缓存的体力消耗倍数
    protected bool m_bEncumbranceCacheValid = false; // 缓存是否有效
    protected SCR_CharacterInventoryStorageComponent m_pCachedInventoryComponent; // 缓存的库存组件引用
    protected SCR_InventoryStorageManagerComponent m_pCachedInventoryManager; // 缓存的库存管理器组件（避免每 tick FindComponent）
    protected float m_fLastCheckTime = 0.0; // 上次检查时间（秒）
    protected const float ENCUMBRANCE_CHECK_INTERVAL = 0.2; // 轮询间隔（秒），结合事件驱动减少 GetTotalWeightOfAllStorages 调用

    // ==================== 公共方法 ====================

    // 初始化缓存
    // @param inventoryComponent 库存组件引用（可为null）
    void Initialize(SCR_CharacterInventoryStorageComponent inventoryComponent = null)
    {
        m_fCachedCurrentWeight = 0.0;
        m_fCachedEncumbranceSpeedPenalty = 0.0;
        m_fCachedBodyMassPercent = 0.0;
        m_fCachedEncumbranceStaminaDrainMultiplier = 1.0;
        m_bEncumbranceCacheValid = false;
        m_pCachedInventoryComponent = inventoryComponent;
        m_pCachedInventoryManager = null;

        // 如果提供了库存组件，初始化时计算一次负重
        if (m_pCachedInventoryComponent)
            UpdateCache();
    }

    // 设置库存组件引用
    // @param inventoryComponent 库存组件引用
    void SetInventoryComponent(SCR_CharacterInventoryStorageComponent inventoryComponent)
    {
        m_pCachedInventoryComponent = inventoryComponent;
        m_pCachedInventoryManager = null; // 重置，下次 UpdateCache 时重新查找
        if (m_pCachedInventoryComponent)
            UpdateCache();
        else
            m_bEncumbranceCacheValid = false;
    }

    // 更新缓存（事件驱动）
    // 仅在库存变化时调用，避免每0.2秒重复计算
    // 注意：需要在库存组件的事件中调用此方法（如 OnItemAdded/OnItemRemoved）
    void UpdateCache()
    {
        if (!m_pCachedInventoryComponent)
        {
            m_bEncumbranceCacheValid = false;
            return;
        }

        float currentWeight = 0.0;

        // 获取角色实体
        IEntity ownerEntity = m_pCachedInventoryComponent.GetOwner();
        if (!ownerEntity)
        {
            m_bEncumbranceCacheValid = false;
            return;
        }

        // 使用 SCR_InventoryStorageManagerComponent.GetTotalWeightOfAllStorages() 方法（唯一方式）
        if (!m_pCachedInventoryManager)
            m_pCachedInventoryManager = SCR_InventoryStorageManagerComponent.Cast(ownerEntity.FindComponent(SCR_InventoryStorageManagerComponent));
        if (m_pCachedInventoryManager)
        {
            // 使用官方推荐的 GetTotalWeightOfAllStorages() 方法，确保计算所有存储的重量
            currentWeight = m_pCachedInventoryManager.GetTotalWeightOfAllStorages();
        }
        else
        {
            // 如果无法获取 inventoryManager，设置缓存无效
            m_bEncumbranceCacheValid = false;
            if (StaminaConstants.IsDebugEnabled())
                Print("[RSS] UpdateCache - 无法获取 SCR_InventoryStorageManagerComponent");
            return;
        }

        if (currentWeight < 0.0)
        {
            m_bEncumbranceCacheValid = false;
            return;
        }

        // 更新缓存值
        m_fCachedCurrentWeight = currentWeight;

        // 计算有效负重（负载 = 载具/装备重量 - 基准装备重量）
        // GetTotalWeightOfAllStorages() 返回的是装备/背包重量，不含身体重量
        float effectiveWeight = Math.Max(currentWeight - StaminaConstants.BASE_WEIGHT, 0.0);
        m_fCachedBodyMassPercent = effectiveWeight / StaminaConstants.CHARACTER_WEIGHT;
        m_fCachedEncumbranceSpeedPenalty = ComputeSpeedPenaltyFromEffectiveWeight(effectiveWeight);

        // 计算体力消耗倍数
        float encumbranceStaminaDrainCoeff = StaminaConstants.GetEncumbranceStaminaDrainCoeff();
        m_fCachedEncumbranceStaminaDrainMultiplier = 1.0 + (encumbranceStaminaDrainCoeff * m_fCachedBodyMassPercent);
        m_fCachedEncumbranceStaminaDrainMultiplier = Math.Clamp(m_fCachedEncumbranceStaminaDrainMultiplier, 1.0, 3.0);

        m_bEncumbranceCacheValid = true;
    }

    // 检查并更新缓存（仅在变化时更新）
    // 在 UpdateSpeedBasedOnStamina 中调用，检查负重是否变化
    // 性能优化：按 ENCUMBRANCE_CHECK_INTERVAL 节流，减少 GetTotalWeightOfAllStorages 调用频率
    void CheckAndUpdate()
    {
        if (!m_pCachedInventoryComponent)
            return;

        float currentTime = GetGame().GetWorld().GetWorldTime() / 1000.0;
        if (m_bEncumbranceCacheValid && (currentTime - m_fLastCheckTime < ENCUMBRANCE_CHECK_INTERVAL))
            return;
        m_fLastCheckTime = currentTime;

        float currentWeight = 0.0;

        // 获取角色实体
        IEntity ownerEntity = m_pCachedInventoryComponent.GetOwner();
        if (ownerEntity)
        {
            if (!m_pCachedInventoryManager)
                m_pCachedInventoryManager = SCR_InventoryStorageManagerComponent.Cast(ownerEntity.FindComponent(SCR_InventoryStorageManagerComponent));
            if (m_pCachedInventoryManager)
            {
                currentWeight = m_pCachedInventoryManager.GetTotalWeightOfAllStorages();
            }
            else
            {
                // 回退方案：手动计算所有必要存储的重量
                array<BaseInventoryStorageComponent> storages = {};
                float weaponWeight = 0.0;
                float characterWeight = 0.0;

                // 按照官方 GetTotalWeightOfAllStorages() 方法的逻辑，手动添加必要的存储
                BaseInventoryStorageComponent weaponStorage = m_pCachedInventoryComponent.GetWeaponStorage();
                storages.Insert(weaponStorage); // 主副武器插槽
                storages.Insert(m_pCachedInventoryComponent);                    // 衣服、背包、背心里的东西

                // 遍历所有存储，累加重量
                foreach (BaseInventoryStorageComponent storage : storages)
                {
                    if (storage)
                    {
                        float storageWeight = storage.GetTotalWeight();
                        currentWeight += storageWeight;

                        if (storage == weaponStorage)
                            weaponWeight = storageWeight;
                        else if (storage == m_pCachedInventoryComponent)
                            characterWeight = storageWeight;
                    }
                }


            }
        }
        else
        {
            // 无角色实体时的回退方案
            float weaponWeight = 0.0;
            currentWeight = m_pCachedInventoryComponent.GetTotalWeight();

            // 添加武器存储重量
            BaseInventoryStorageComponent weaponStorage = m_pCachedInventoryComponent.GetWeaponStorage();
            if (weaponStorage)
            {
                weaponWeight = weaponStorage.GetTotalWeight();
                currentWeight += weaponWeight;
            }


        }

        // 如果重量变化超过0.1kg，重新计算缓存（避免微小浮点误差触发）
        if (Math.AbsFloat(currentWeight - m_fCachedCurrentWeight) > 0.1 || !m_bEncumbranceCacheValid)
        {
            UpdateCache();
        }
    }

    // ==================== 获取缓存值的方法 ====================

    // 获取缓存的当前重量
    // @return 当前重量（kg），如果缓存无效则返回0.0
    float GetCurrentWeight()
    {
        if (m_bEncumbranceCacheValid)
            return m_fCachedCurrentWeight;
        return 0.0;
    }

    // 获取缓存的速度惩罚
    // @return 速度惩罚值（0.0-0.5），如果缓存无效则返回0.0
    float GetSpeedPenalty()
    {
        if (m_bEncumbranceCacheValid)
            return m_fCachedEncumbranceSpeedPenalty;
        return 0.0;
    }

    // 获取缓存的有效负重占体重百分比
    // @return 有效负重占体重百分比（0.0-1.0+），如果缓存无效则返回0.0
    float GetBodyMassPercent()
    {
        if (m_bEncumbranceCacheValid)
            return m_fCachedBodyMassPercent;
        return 0.0;
    }

    // 获取缓存的体力消耗倍数
    // @return 体力消耗倍数（1.0-3.0），如果缓存无效则返回1.0
    float GetStaminaDrainMultiplier()
    {
        if (m_bEncumbranceCacheValid)
            return m_fCachedEncumbranceStaminaDrainMultiplier;
        return 1.0;
    }

    // 检查缓存是否有效
    // @return true表示缓存有效，false表示缓存无效
    bool IsCacheValid()
    {
        return m_bEncumbranceCacheValid;
    }

    // 获取库存组件引用
    // @return 库存组件引用（可为null）
    SCR_CharacterInventoryStorageComponent GetInventoryComponent()
    {
        return m_pCachedInventoryComponent;
    }
}

// 速度计算模块
// 负责计算基础速度倍数、移动类型处理、Sprint速度计算等
// 模块化拆分：从 PlayerBase.c 提取的速度计算逻辑

// 坡度计算结果结构体
class GradeCalculationResult
{
    float gradePercent;
    float slopeAngleDegrees;
}

class SpeedCalculator
{
    protected static ref GradeCalculationResult s_pResultGrade;

    // ==================== 公共方法 ====================

    // 计算基础速度倍数（根据体力百分比）
    // @param staminaPercent 当前体力百分比 (0.0-1.0)
    // @param collapseTransition "撞墙"阻尼过渡模块引用
    // @param currentWorldTime 当前世界时间
    // @return 基础速度倍数
    static float CalculateBaseSpeedMultiplier(float staminaPercent, CollapseTransition collapseTransition, float currentWorldTime)
    {
        // 更新"撞墙"阻尼过渡模块状态
        if (collapseTransition)
            collapseTransition.Update(currentWorldTime, staminaPercent);

        // 先计算正常情况下的基础速度倍数
        float normalBaseSpeedMultiplier = RealisticStaminaSpeedSystem.CalculateSpeedMultiplierByStamina(staminaPercent);

        // 如果处于5秒阻尼过渡期间，使用模块计算过渡速度
        if (collapseTransition && collapseTransition.IsInTransition())
        {
            return collapseTransition.CalculateTransitionSpeedMultiplier(currentWorldTime, normalBaseSpeedMultiplier);
        }

        return normalBaseSpeedMultiplier;
    }

    // 计算坡度自适应目标速度
    // @param baseTargetSpeed 基础目标速度 (m/s)
    // @param slopeAngleDegrees 坡度角度（度）
    // @return 坡度自适应后的目标速度 (m/s)
    static float CalculateSlopeAdjustedTargetSpeed(float baseTargetSpeed, float slopeAngleDegrees)
    {
        return RealisticStaminaSpeedSystem.CalculateSlopeAdjustedTargetSpeed(baseTargetSpeed, slopeAngleDegrees);
    }

    // 计算最终绝对速度（米/秒）- 仅在Run和Sprint模式下
    // @param runBaseSpeedMultiplier Run的基础速度倍数
    // @param encumbranceSpeedPenalty 负重速度惩罚（基础惩罚项）
    // @param isSprinting 是否正在Sprint
    // @param currentMovementPhase 当前移动阶段 (0=idle, 1=walk, 2=run, 3=sprint)
    // @param isExhausted 是否精疲力尽
    // @param canSprint 是否可以Sprint
    // @param staminaPercent 当前体力百分比
    // @param currentSpeed 当前速度 (m/s)
    // @param currentWorldTime 当前世界时间（秒），用于战术冲刺爆发期判断，-1 表示不参与
    // @param sprintStartTime 本次冲刺开始时间（秒），-1 表示未在冲刺
    // @return 最终绝对速度（米/秒），非Run/Sprint模式返回-1
    static float CalculateFinalAbsoluteSpeed(
        float runBaseSpeedMultiplier,
        float encumbranceSpeedPenalty,
        bool isSprinting,
        int currentMovementPhase,
        bool isExhausted,
        bool canSprint,
        float staminaPercent,
        float currentSpeed = 0.0,
        float currentWorldTime = -1.0,
        float sprintStartTime = -1.0)
    {
        // 如果精疲力尽，禁用Sprint
        if (isExhausted || !canSprint)
        {
            if (isSprinting || currentMovementPhase == 3)
            {
                currentMovementPhase = 2; // 强制切换到Run
                isSprinting = false;
            }
        }

        // 只处理Run和Sprint模式，其他模式返回-1表示不接管
        if (currentMovementPhase != 2 && currentMovementPhase != 3 && !isSprinting)
        {
            return -1.0;
        }

        // runBaseSpeedMultiplier 已由调用方按坡度完成缩放，此处无需再次应用坡度
        float scaledRunSpeed = runBaseSpeedMultiplier;

        float finalAbsoluteSpeed = 0.0;

        // 负重速度惩罚（含速度相关项与Sprint额外惩罚）
        float speedRatio = Math.Clamp(currentSpeed / RealisticStaminaSpeedSystem.GAME_MAX_SPEED, 0.0, 1.0);
        float encumbrancePenalty = encumbranceSpeedPenalty * (1.0 + speedRatio);
        if (isSprinting || currentMovementPhase == 3)
            encumbrancePenalty = encumbrancePenalty * 1.5;
        float maxPenalty = StaminaConstants.GetEncumbranceSpeedPenaltyMax();
        encumbrancePenalty = Math.Clamp(encumbrancePenalty, 0.0, maxPenalty);

        // 战术冲刺爆发期 + 缓冲区：前 8s 爆发，8s 后 5s 内线性过渡到平稳期
        if ((isSprinting || currentMovementPhase == 3) && currentWorldTime >= 0.0 && sprintStartTime >= 0.0)
        {
            float burstDuration = StaminaConstants.GetTacticalSprintBurstDuration();
            float bufferDuration = StaminaConstants.GetTacticalSprintBurstBufferDuration();
            float elapsed = currentWorldTime - sprintStartTime;
            if (burstDuration > 0.0 && elapsed <= burstDuration)
            {
                float burstFactor = StaminaConstants.GetTacticalSprintBurstEncumbranceFactor();
                encumbrancePenalty = encumbrancePenalty * burstFactor;
            }
            else if (bufferDuration > 0.0 && elapsed > burstDuration && elapsed <= burstDuration + bufferDuration)
            {
                float burstFactor = StaminaConstants.GetTacticalSprintBurstEncumbranceFactor();
                float t = (elapsed - burstDuration) / bufferDuration;
                t = Math.Clamp(t, 0.0, 1.0);
                float blendFactor = burstFactor + (1.0 - burstFactor) * t;
                encumbrancePenalty = encumbrancePenalty * blendFactor;
            }
        }

        if (isSprinting || currentMovementPhase == 3) // Sprint
        {
            // Sprint理论目标速度（不含负重惩罚）= GAME_MAX_SPEED × scaledRunSpeed × (1 + 30%)
            // 注意：scaledRunSpeed 相对于 GAME_MAX_SPEED 的倍数
            // 负重惩罚将在 UpdateSpeed 中通过补偿倍数的方式应用
            float sprintSpeedBoost = StaminaConstants.GetSprintSpeedBoost();
            finalAbsoluteSpeed = RealisticStaminaSpeedSystem.GAME_MAX_SPEED * scaledRunSpeed * (1.0 + sprintSpeedBoost);
            // 限制速度在合理范围内
            finalAbsoluteSpeed = Math.Clamp(finalAbsoluteSpeed, 0.8, RealisticStaminaSpeedSystem.GAME_MAX_SPEED);
        }
        else if (currentMovementPhase == 2) // Run
        {
            // Run理论目标速度（不含负重惩罚）= TARGET_RUN_SPEED × (scaledRunSpeed / TARGET_RUN_SPEED_MULTIPLIER)
            // 注意：scaledRunSpeed 原本相对于 GAME_MAX_SPEED，需要转换为相对于 TARGET_RUN_SPEED
            // 负重惩罚将在 UpdateSpeed 中通过补偿倍数的方式应用
            float normalizedScaledRunSpeed = scaledRunSpeed / RealisticStaminaSpeedSystem.TARGET_RUN_SPEED_MULTIPLIER;
            finalAbsoluteSpeed = RealisticStaminaSpeedSystem.TARGET_RUN_SPEED * normalizedScaledRunSpeed;
            // 限制速度在合理范围内
            finalAbsoluteSpeed = Math.Clamp(finalAbsoluteSpeed, 0.8, RealisticStaminaSpeedSystem.TARGET_RUN_SPEED);
        }

        // 静止起步检测：如果当前速度很低但处于移动阶段，给予起步补偿
        if (currentSpeed < 0.5)
        {
            // 给予起步补偿，防止瞬时限速导致的起步无力
            finalAbsoluteSpeed = Math.Max(finalAbsoluteSpeed, 2.5);
        }

        return finalAbsoluteSpeed;
    }

    // 计算最终速度倍数（根据移动类型）- 保持向后兼容
    // @param runBaseSpeedMultiplier Run的基础速度倍数
    // @param encumbranceSpeedPenalty 负重速度惩罚（基础惩罚项）
    // @param isSprinting 是否正在Sprint
    // @param currentMovementPhase 当前移动阶段 (0=idle, 1=walk, 2=run, 3=sprint)
    // @param isExhausted 是否精疲力尽
    // @param canSprint 是否可以Sprint
    // @param staminaPercent 当前体力百分比
    // @param currentSpeed 当前速度 (m/s)
    // @param currentWorldTime 当前世界时间（秒），用于战术冲刺爆发期判断，-1 表示不参与
    // @param sprintStartTime 本次冲刺开始时间（秒），-1 表示未在冲刺
    // @return 最终速度倍数
    static float CalculateFinalSpeedMultiplier(
        float runBaseSpeedMultiplier,
        float encumbranceSpeedPenalty,
        bool isSprinting,
        int currentMovementPhase,
        bool isExhausted,
        bool canSprint,
        float staminaPercent,
        float currentSpeed = 0.0,
        float currentWorldTime = -1.0,
        float sprintStartTime = -1.0)
    {
        // 如果精疲力尽，禁用Sprint
        if (isExhausted || !canSprint)
        {
            if (isSprinting || currentMovementPhase == 3)
            {
                currentMovementPhase = 2; // 强制切换到Run
                isSprinting = false;
            }
        }

        // runBaseSpeedMultiplier 已由调用方（UpdateSpeed / CalculateFinalSpeedMultiplierFromInputs）
        // 按坡度完成缩放，此处无需再次应用坡度，直接使用
        float scaledRunSpeed = runBaseSpeedMultiplier;

        float finalSpeedMultiplier = 0.0;

        // 负重速度惩罚（含速度相关项与Sprint额外惩罚）
        float speedRatio = Math.Clamp(currentSpeed / RealisticStaminaSpeedSystem.GAME_MAX_SPEED, 0.0, 1.0);
        float encumbrancePenalty = encumbranceSpeedPenalty * (1.0 + speedRatio);
        if (isSprinting || currentMovementPhase == 3)
            encumbrancePenalty = encumbrancePenalty * 1.5;
        float maxPenalty = StaminaConstants.GetEncumbranceSpeedPenaltyMax();
        encumbrancePenalty = Math.Clamp(encumbrancePenalty, 0.0, maxPenalty);

        // 战术冲刺爆发期 + 缓冲区：前 8s 爆发，8s 后 5s 内线性过渡到平稳期
        if ((isSprinting || currentMovementPhase == 3) && currentWorldTime >= 0.0 && sprintStartTime >= 0.0)
        {
            float burstDuration = StaminaConstants.GetTacticalSprintBurstDuration();
            float bufferDuration = StaminaConstants.GetTacticalSprintBurstBufferDuration();
            float elapsed = currentWorldTime - sprintStartTime;
            if (burstDuration > 0.0 && elapsed <= burstDuration)
            {
                float burstFactor = StaminaConstants.GetTacticalSprintBurstEncumbranceFactor();
                encumbrancePenalty = encumbrancePenalty * burstFactor;
            }
            else if (bufferDuration > 0.0 && elapsed > burstDuration && elapsed <= burstDuration + bufferDuration)
            {
                float burstFactor = StaminaConstants.GetTacticalSprintBurstEncumbranceFactor();
                float t = (elapsed - burstDuration) / bufferDuration;
                t = Math.Clamp(t, 0.0, 1.0);
                float blendFactor = burstFactor + (1.0 - burstFactor) * t;
                encumbrancePenalty = encumbrancePenalty * blendFactor;
            }
        }

        if (isSprinting || currentMovementPhase == 3) // Sprint
        {
            // Sprint速度 = Run基础倍率 × (1 + 30%)
            float sprintSpeedBoost = StaminaConstants.GetSprintSpeedBoost();
            float sprintMultiplier = 1.0 + sprintSpeedBoost; // 1.30
            finalSpeedMultiplier = (scaledRunSpeed * sprintMultiplier) * (1.0 - encumbrancePenalty);
            finalSpeedMultiplier = Math.Clamp(finalSpeedMultiplier, 0.15, 1.0);
        }
        else if (currentMovementPhase == 2) // Run
        {
            finalSpeedMultiplier = scaledRunSpeed * (1.0 - encumbrancePenalty);
            finalSpeedMultiplier = Math.Clamp(finalSpeedMultiplier, 0.15, 1.0);
        }
        else if (currentMovementPhase == 1) // Walk
        {
            float walkBaseSpeedMultiplier = RealisticStaminaSpeedSystem.CalculateSpeedMultiplierByStamina(staminaPercent);
            finalSpeedMultiplier = (walkBaseSpeedMultiplier * 0.8) * (1.0 - encumbrancePenalty); // 提高Walk基础速度

            // 放宽Walk阶段的速度限制范围
            finalSpeedMultiplier = Math.Clamp(finalSpeedMultiplier, 0.2, 0.9);
        }
        else // Idle
        {
            finalSpeedMultiplier = 0.0;
        }

        // 静止起步检测：如果当前速度很低但处于移动阶段，给予起步补偿
        bool isMovingPhase = (currentMovementPhase == 1 || currentMovementPhase == 2 || currentMovementPhase == 3);
        if (isMovingPhase && currentSpeed < 0.5)
        {
            // 给予起步补偿，防止瞬时限速导致的起步无力
            finalSpeedMultiplier = Math.Max(finalSpeedMultiplier, 0.5);
        }

        return finalSpeedMultiplier;
    }

    // 速度阈值（m/s）：低于此值视为静止，有效坡度按 0 处理（无运动方向）
    protected static const float VELOCITY_SIGN_THRESHOLD = 0.1;
    // [仅用于 GetSlopeSignFromVelocity 等] 等高线判定阈值；有效坡度已改为“幅值×cos(速度与上坡夹角)”，等高线自然为 0
    protected static const float CONTOUR_COS_THRESHOLD = 0.2;

    // 通过地面法线计算地形坡度幅值（与移动方向无关）
    // @param controller 角色控制器组件
    // @return 坡度角度幅值（0..45 度），失败返回 0
    static float GetTerrainSlopeAngleMagnitude(SCR_CharacterControllerComponent controller)
    {
        if (!controller)
            return 0.0;
        IEntity owner = controller.GetOwner();
        if (!owner)
            return 0.0;
        BaseWorld world = owner.GetWorld();
        if (!world)
            return 0.0;
        vector pos = owner.GetOrigin();
        vector normal = SCR_TerrainHelper.GetTerrainNormal(pos, world, false, null);
        float dotUp = vector.Dot(normal, vector.Up);
        dotUp = Math.Clamp(dotUp, 0.0, 1.0);
        float slopeAngleDegrees = Math.Acos(dotUp) * Math.RAD2DEG;
        return Math.Clamp(slopeAngleDegrees, 0.0, 45.0);
    }

    // 根据速度矢量与坡向得到“沿运动方向”的投影系数 cos(速度与上坡夹角)
    // 用于计算有效坡度：effectiveSlopeDeg = magnitude × cosAngle（Pandolf 的 G 应为运动方向上的 rise/run）
    // 上坡方向 = 法线水平分量的反方向；cosAngle=1 直上坡，-1 直下坡，0 等高线
    // @param normal 地面法线
    // @param velocity 速度矢量（水平分量参与）
    // @return cos(夹角)，范围 [-1,1]；静止或平地时返回 0
    static float GetSlopeProjectionCos(vector normal, vector velocity)
    {
        vector horizontalVel = velocity;
        horizontalVel[1] = 0.0;
        float velLen = horizontalVel.Length();
        if (velLen < VELOCITY_SIGN_THRESHOLD)
            return 0.0;
        vector horizontalNormal = normal;
        horizontalNormal[1] = 0.0;
        float hLen = horizontalNormal.Length();
        if (hLen < 0.001)
            return 0.0;
        vector uphillDir = horizontalNormal * (-1.0 / hLen);
        float cosAngle = vector.Dot(horizontalVel, uphillDir) / velLen;
        return Math.Clamp(cosAngle, -1.0, 1.0);
    }

    // 根据速度矢量与坡向判断上/下坡符号（仅用于需二值判断的场合，如 HUD）
    // 上坡方向 = 法线水平分量的反方向；沿等高线视为上坡
    // @param normal 地面法线
    // @param velocity 速度矢量（水平分量参与判断）
    // @return +1 上坡/等高线，-1 下坡，静止时 +1
    static int GetSlopeSignFromVelocity(vector normal, vector velocity)
    {
        float cosAngle = GetSlopeProjectionCos(normal, velocity);
        if (cosAngle > CONTOUR_COS_THRESHOLD)
            return 1;
        if (cosAngle < -CONTOUR_COS_THRESHOLD)
            return -1;
        return 1;
    }

    // 获取原始坡度角度（不做室内归零，供室内楼梯判定等使用）
    // 使用“运动方向有效坡度”：幅值由地形法线得到，再投影到速度方向（magnitude × cos(速度与上坡夹角)），
    // 使沿等高线移动时坡度为 0、斜向移动时坡度按几何比例缩放，与 Pandolf 的“沿路径坡度”一致，避免法线全幅导致的不合理。
    // @param controller 角色控制器组件
    // @param velocity 速度矢量（可选，vector.Zero 时从 controller 获取；静止时有效坡度=0）
    // @return 有效坡度角度（度），正=上坡，负=下坡，0=平地/等高线/静止
    static float GetRawSlopeAngle(SCR_CharacterControllerComponent controller, vector velocity = vector.Zero)
    {
        if (!controller)
            return 0.0;
        IEntity owner = controller.GetOwner();
        if (!owner)
            return 0.0;
        float magnitude = GetTerrainSlopeAngleMagnitude(controller);
        if (magnitude < 0.01)
            return 0.0;
        vector pos = owner.GetOrigin();
        vector normal = SCR_TerrainHelper.GetTerrainNormal(pos, owner.GetWorld(), false, null);
        if (velocity.Length() < VELOCITY_SIGN_THRESHOLD)
            velocity = controller.GetVelocity();
        float cosAngle = GetSlopeProjectionCos(normal, velocity);
        float effectiveSlopeDegrees = magnitude * cosAngle;
        return Math.Clamp(effectiveSlopeDegrees, -45.0, 45.0);
    }

    // 获取坡度角度（完全用法线坡度 + 速度矢量判断上下坡）
    // 此方法直接返回坡度角度，单位为度。
    // @param controller 角色控制器组件
    // @param environmentFactor 环境因子组件（可选，用于室内检测)
    // @param velocity 速度矢量（可选，用于判断上下坡）
    // @return 坡度角度（度）
    static float GetSlopeAngle(SCR_CharacterControllerComponent controller, EnvironmentFactor environmentFactor = null, vector velocity = vector.Zero)
    {
        if (environmentFactor && controller)
        {
            IEntity ownerForCheck = controller.GetOwner();
            if (ownerForCheck && environmentFactor.ShouldSuppressTerrainSlopeForEntity(ownerForCheck))
                return 0.0;
        }
        return GetRawSlopeAngle(controller, velocity);
    }

    // 计算坡度百分比（考虑攀爬和跳跃状态）
    // 返回值中的 gradePercent 为坡度的百分比（rise/run × 100）。
    // 注意：原始角度由 GetSlopeAngle 返回（度），需要通过 tan() 转换。
    // @param controller 角色控制器组件
    // @param currentSpeed 当前速度（m/s）
    // @param jumpVaultDetector 跳跃检测器（可选）
    // @param slopeAngleDegrees 坡度角度（输入，通常为0.0；输出会被替换）
    // @param environmentFactor 环境因子组件（可选，用于室内检测）
    // @param velocity 速度矢量（可选，用于判断上下坡，游泳时传 computedVelocity）
    // @return 坡度计算结果（包含坡度百分比和角度）
    static GradeCalculationResult CalculateGradePercent(
        SCR_CharacterControllerComponent controller,
        float currentSpeed,
        JumpVaultDetector jumpVaultDetector,
        float slopeAngleDegrees,
        EnvironmentFactor environmentFactor = null,
        vector velocity = vector.Zero)
    {
        if (!s_pResultGrade)
            s_pResultGrade = new GradeCalculationResult();
        s_pResultGrade.gradePercent = 0.0;
        s_pResultGrade.slopeAngleDegrees = slopeAngleDegrees;

        // 完整室内或建筑物内有顶体积：返回零坡度（与 GetSlopeAngle 一致）
        if (environmentFactor && controller)
        {
            IEntity ownerForCheck = controller.GetOwner();
            if (ownerForCheck && environmentFactor.ShouldSuppressTerrainSlopeForEntity(ownerForCheck))
            {
                s_pResultGrade.slopeAngleDegrees = 0.0;
                return s_pResultGrade;
            }
        }

        // 检查是否在攀爬或跳跃状态
        bool isClimbingForSlope = controller.IsClimbing();
        bool isJumpingForSlope = false;
        if (jumpVaultDetector)
            isJumpingForSlope = jumpVaultDetector.GetJumpInputTriggered();

        // 只在非攀爬、非跳跃状态下获取坡度
        if (!isClimbingForSlope && !isJumpingForSlope && currentSpeed > 0.05)
        {
            // 获取坡度角度并转换为坡度百分比（传入 velocity 用于判断上下坡）
            float rawAngleDeg = GetSlopeAngle(controller, environmentFactor, velocity);
            s_pResultGrade.slopeAngleDegrees = rawAngleDeg;
            // 将角度转换为斜率比：tan(angle_rad)
            float slopeRatio = Math.Tan(rawAngleDeg * Math.DEG2RAD);
            // Clamp ratio to reasonable range (-100%..100%) to avoid terrain/measurement glitches
            if (slopeRatio < -1.0 || slopeRatio > 1.0)
            {
                // log warning once per debug cycle
                if (StaminaConstants.IsDebugEnabled())
                slopeRatio = Math.Clamp(slopeRatio, -1.0, 1.0);
            }
            s_pResultGrade.gradePercent = slopeRatio * 100.0;
            if (StaminaConstants.IsDebugEnabled())
            {
            }
        }

        return s_pResultGrade;
    }
}

// 环境因子模块
// 负责处理环境因素对体力系统的影响（热应激、降雨湿重等）
// 模块化拆分：从 PlayerBase.c 提取的独立功能模块

class EnvironmentFactor
{
    // ==================== 状态变量 ====================
    protected float m_fCachedHeatStressMultiplier = 1.0; // 缓存的热应激倍数
    protected float m_fCachedRainWeight = 0.0; // 缓存的降雨湿重（kg）
    protected float m_fLastEnvironmentCheckTime = 0.0; // 上次环境检测时间
    protected float m_fRainStopTime = -1.0; // 停止降雨的时间（用于湿重衰减）
    protected TimeAndWeatherManagerEntity m_pCachedWeatherManager; // 缓存的天气管理器引用
    protected float m_fLastRainIntensity = 0.0; // 上次检测到的降雨强度（用于衰减计算）
    protected IEntity m_pCachedOwner; // 缓存的角色实体引用（用于室内检测）

    // 实时变更检测缓存（用于即时响应管理员修改）
    protected float m_fLastKnownTOD = -1.0; // 上次记录的 GetTimeOfTheDay 值
    protected int m_iLastKnownYear = -1;
    protected int m_iLastKnownMonth = -1;
    protected int m_iLastKnownDay = -1;
    protected float m_fLastKnownRainIntensity = -1.0;
    protected float m_fLastKnownWindSpeed = -1.0;
    protected bool m_bLastKnownOverrideTemperature = false;
    protected float m_fLastKnownSunriseHour = -1.0;
    protected float m_fLastKnownSunsetHour = -1.0;

    // ==================== 高级环境因子状态变量（v2.15.0）====================
    protected float m_fCachedRainIntensity = 0.0; // 缓存的降雨强度（0.0-1.0）
    protected float m_fCachedWindSpeed = 0.0; // 缓存的风速（m/s）
    protected float m_fCachedWindDirection = 0.0; // 缓存的风向（度）
    protected float m_fCachedWindDrag = 0.0; // 缓存的风阻系数
    protected float m_fCachedMudFactor = 0.0; // 缓存的泥泞度系数（0.0-1.0）
    protected float m_fCachedTemperature = 20.0; // 缓存的当前气温（°C）
    protected float m_fCachedSurfaceWetness = 0.0; // 缓存的地表湿度（0.0-1.0）
    protected float m_fCurrentTotalWetWeight = 0.0; // 当前总湿重（游泳+降雨，kg）
    protected float m_fLastUpdateTime = 0.0; // 上次更新时间（秒）
    protected float m_fRainBreathingPenalty = 0.0; // 暴雨呼吸阻力惩罚
    protected float m_fCachedTerrainFactor = 1.0; // 缓存的地形系数
    protected float m_fMudTerrainFactor = 0.0; // 泥泞地形系数惩罚
    protected float m_fMudSprintPenalty = 0.0; // 泥泞Sprint惩罚
    protected float m_fSlipRisk = 0.0; // 滑倒风险
    protected float m_fHeatStressPenalty = 0.0; // 热应激惩罚
    protected float m_fColdStressPenalty = 0.0; // 冷应激惩罚
    protected float m_fColdStaticPenalty = 0.0; // 冷应激静态惩罚
    // ==================== 室内检测相关变量 ====================
    protected float m_fLastIndoorCheckTime = 0.0; // 上次室内检测时间
    protected const float INDOOR_CHECK_INTERVAL = 1.0; // 室内检测间隔（秒）
    protected bool m_bCachedIndoorState = false; // 缓存的室内状态
    protected bool m_bCachedRoofedVolumeForSlopeState = false; // 建筑物内有顶（不要求水平封闭），用于压制楼梯间地形坡度
    protected ref array<IEntity> m_pCachedBuildings; // 缓存的建筑物列表（用于回调）
    protected ref TraceParam m_pTraceParamRoof; // 复用的 TraceParam（RaycastHasRoof）
    protected ref TraceParam m_pTraceParamEnclosed; // 复用的 TraceParam（IsHorizontallyEnclosed）
    protected float m_fSurfaceWetnessPenalty = 0.0; // 地表湿度惩罚

    // 调试开关：启用后输出室内检测的详细日志
    protected bool m_bIndoorDebug = false; // 默认关闭

    // 是否使用引擎天气API（true=使用引擎数据，false=使用虚拟昼夜模型）
    protected bool m_bUseEngineWeather = true; // 默认启用真实天气

    // ====== 温度计算相关参数（P1 实现） ======
    protected float m_fTempUpdateInterval = 5.0; // 温度步进间隔（秒），默认5s（实时每5秒更新）
    protected float m_fLastTemperatureUpdateTime = 0.0; // 上次温度更新时间（秒）

    // 位置变化触发温度重算（v3.20.0 性能优化）
    // 玩家移动超过阈值时提前触发，静止时回退到时间间隔，减少不必要的重算
    protected vector m_vLastTempCalcPosition = vector.Zero; // 上次温度计算时的位置
    protected bool m_bTempPositionInitialized = false;      // 位置是否已初始化
    protected const float TEMP_RECALC_DISTANCE_SQ = 10000.0; // 100m² → 100m 触发（存储平方值避免 sqrt）
    protected float m_fNextTempStepLogTime = 0.0; // 下次非详细温度步进日志时间（用于 ShouldLog）
    protected bool m_bPendingForceUpdate = false; // 标记是否有管理员触发的即时温度重算请求
    protected float m_fNextForceUpdateLogTime = 0.0; // ForceUpdate 日志节流时间（避免传字面量给 ShouldLog）
    protected float m_fNextLocationEstimateLogTime = 0.0; // 位置估算日志节流（避免直接传入字面量）
    // 是否使用引擎提供的温度（独立于 m_bUseEngineWeather）
    protected bool m_bUseEngineTemperature = false; // 默认不使用引擎温度，完全通过模组内计算
    protected float m_fTemperatureMixingHeight = 1000.0; // 混合层高度（m），用于热容量计算
    protected float m_fAlbedo = 0.2; // 地表反照率（默认：草地/混合地表）
    protected float m_fAerosolOpticalDepth = 0.14; // 简化的大气光学厚度用于透过率估计
    protected float m_fSurfaceEmissivity = 0.98; // 地表发射率
    protected float m_fCachedSurfaceTemperature = 20.0; // 缓存的近地面温度（°C）

    // 物理模型可调系数（可从 SCR_RSS_Settings 读取）
    protected float m_fCloudBlockingCoeff = 0.7; // 云层遮挡短波的系数（经验）
    protected float m_fLECoef = 200.0; // 潜热系数（W/m2 每单位地表湿度）

    // 通用气温模型参数（正弦波叠加，兼容各模组地图）
    protected float m_fAltitudeMeters = 0.0; // 海拔（m），缺省 0
    protected float m_fFogDensity = 0.0; // 雾/湿度 (0~1)，用于压缩昼夜温差，缺省 0

    // 时区/经度用于太阳时校正
    protected bool m_bUseEngineTimezone = true; // 是否优先使用引擎时区信息
    protected float m_fLongitude = 0.0; // 经度覆盖（度）
    protected float m_fLatitude = 0.0; // 纬度覆盖（度）
    protected float m_fTimeZoneOffsetHours = 0.0; // 时区偏移覆盖（小时）

    protected float m_fSolarConstant = 1361.0; // 太阳常数（W/m^2）
    protected const float STEFAN_BOLTZMANN = 5.670374419e-8; // 斯特藩-玻尔兹曼常数
    protected const float M_E = 2.718281828459045; // 自然常数 e（用于替代 Math.Exp）
