    // 计算泥泞Sprint惩罚
    protected void CalculateMudSprintPenalty()
    {
        m_fMudSprintPenalty = SCR_EnvironmentPenaltyMath.CalculateMudSprintPenalty(m_fCachedMudFactor);
    }

    // 计算滑倒风险
    protected void CalculateSlipRisk()
    {
        m_fSlipRisk = SCR_EnvironmentPenaltyMath.CalculateSlipRisk(m_fCachedMudFactor);
    }

    // 计算热应激惩罚
    protected void CalculateHeatStressPenalty()
    {
        m_fHeatStressPenalty = SCR_EnvironmentPenaltyMath.CalculateHeatStressPenalty(m_fCachedTemperature);
    }

    // 根据当前环境温度和风速对机械能耗进行补偿
    // @param basePower 运动机械功率 (J/s)
    // @return 包含热调节的总功率 (J/s)
    float AdjustEnergyForTemperature(float basePower)
    {
        return SCR_EnvironmentPenaltyMath.AdjustEnergyForTemperature(basePower, m_fCachedTemperature, m_fCachedWindSpeed);
    }

    // 计算冷应激惩罚
    protected void CalculateColdStressPenalty()
    {
        SCR_EnvironmentPenaltyMath.CalculateColdStressPenalty(m_fCachedTemperature, m_fColdStressPenalty, m_fColdStaticPenalty);
    }

    // 计算地表湿度惩罚
    // @param owner 角色实体
    // @param stance 当前姿态（0=站立，1=蹲姿，2=趴姿）
    protected void CalculateSurfaceWetnessPenalty(IEntity owner, int stance = 0)
    {
        if (!owner)
            return;

        m_fSurfaceWetnessPenalty = SCR_EnvironmentPenaltyMath.CalculateSurfaceWetnessPenalty(m_fCachedSurfaceWetness, stance);
    }
}

//! 环境惩罚计算工具（从 SCR_EnvironmentFactor.c 拆分）
class SCR_EnvironmentPenaltyMath
{
    static float CalculateRainBreathingPenalty(float rainIntensity)
    {
        if (rainIntensity < StaminaConstants.ENV_RAIN_INTENSITY_HEAVY_THRESHOLD)
            return 0.0;

        return StaminaConstants.ENV_RAIN_INTENSITY_BREATHING_PENALTY
            * (rainIntensity - StaminaConstants.ENV_RAIN_INTENSITY_HEAVY_THRESHOLD);
    }

    static float CalculateMudTerrainFactor(float terrainFactor, float mudFactor)
    {
        if (terrainFactor <= 1.0)
            return 0.0;

        return mudFactor * StaminaConstants.ENV_MUD_PENALTY_MAX;
    }

    static float CalculateMudSprintPenalty(float mudFactor)
    {
        if (mudFactor < StaminaConstants.ENV_MUD_SLIPPERY_THRESHOLD)
            return 0.0;

        return StaminaConstants.ENV_MUD_SPRINT_PENALTY * mudFactor;
    }

    static float CalculateSlipRisk(float mudFactor)
    {
        if (!StaminaConstants.IsMudSlipMechanismEnabled())
            return 0.0;
        if (mudFactor < StaminaConstants.ENV_MUD_SLIPPERY_THRESHOLD)
            return 0.0;

        return StaminaConstants.ENV_MUD_SLIP_RISK_BASE * mudFactor;
    }

    static float CalculateHeatStressPenalty(float temperature)
    {
        if (temperature <= StaminaConstants.ENV_TEMPERATURE_HEAT_THRESHOLD)
            return 0.0;

        float heatPenaltyCoeff = StaminaConstants.GetEnvTemperatureHeatPenaltyCoeff();
        return (temperature - StaminaConstants.ENV_TEMPERATURE_HEAT_THRESHOLD) * heatPenaltyCoeff;
    }

    static void CalculateColdStressPenalty(float temperature, out float coldStressPenalty, out float coldStaticPenalty)
    {
        if (temperature >= StaminaConstants.ENV_TEMPERATURE_COLD_THRESHOLD)
        {
            coldStressPenalty = 0.0;
            coldStaticPenalty = 0.0;
            return;
        }

        float coldRecoveryPenaltyCoeff = StaminaConstants.GetEnvTemperatureColdRecoveryPenaltyCoeff();
        coldStressPenalty = (StaminaConstants.ENV_TEMPERATURE_COLD_THRESHOLD - temperature) * coldRecoveryPenaltyCoeff;
        coldStaticPenalty = (StaminaConstants.ENV_TEMPERATURE_COLD_THRESHOLD - temperature) * StaminaConstants.ENV_TEMPERATURE_COLD_STATIC_PENALTY;
    }

    static float CalculateSurfaceWetnessPenalty(float surfaceWetness, int stance)
    {
        if (stance != 2)
            return 0.0;
        if (surfaceWetness < StaminaConstants.ENV_SURFACE_WETNESS_THRESHOLD)
            return 0.0;

        float surfaceWetnessPenaltyMax = StaminaConstants.GetEnvSurfaceWetnessPenaltyMax();
        return surfaceWetnessPenaltyMax * surfaceWetness;
    }

    static float AdjustEnergyForTemperature(float basePower, float temperature, float windSpeed)
    {
        float tEff = temperature - 1.35 * Math.Sqrt(windSpeed);
        float extraWatts = 0.0;
        const float T_LOW = 18.0;
        const float T_HIGH = 27.0;

        if (tEff < T_LOW)
        {
            float dt = T_LOW - tEff;
            extraWatts = 0.15 * (dt * dt);
        }
        else if (tEff > T_HIGH)
        {
            float dtHot = tEff - T_HIGH;
            extraWatts = 2.0 * (dtHot * dtHot);
        }

        float coeff = StaminaConstants.GetEnergyToStaminaCoeff();
        float extraPerTick = extraWatts * coeff * 0.2;
        return basePower + extraPerTick;
    }
}

// 负重缓存管理模块
// 负责管理负重的缓存计算和更新（事件驱动，性能优化）
// 模块化拆分：从 PlayerBase.c 提取的独立功能模块

class EncumbranceCache
{
    // 与 UpdateCache 内分段多项式一致，供服务器 RPC 等在缓存无效时复用
    static float ComputeSpeedPenaltyFromEffectiveWeight(float effectiveWeight)
    {
        float ratio = Math.Clamp(effectiveWeight / StaminaConstants.CHARACTER_WEIGHT, 0.0, 2.0);
        float rawPenalty = 0.0;
        if (ratio <= 0.3)
        {
            rawPenalty = 0.15 * ratio;
        }
        else if (ratio <= 0.6)
        {
            float segment = ratio - 0.3;
            rawPenalty = 0.045 + 0.35 * Math.Pow(segment, 1.5);
        }
        else
        {
            float segment = ratio - 0.6;
            rawPenalty = 0.25 + 0.65 * (segment * segment);
        }
        float coeff = StaminaConstants.GetEncumbranceSpeedPenaltyCoeff();
        rawPenalty = rawPenalty * (coeff / 0.20);
        float max_pen = StaminaConstants.GetEncumbranceSpeedPenaltyMax();
        return Math.Clamp(rawPenalty, 0.0, max_pen);
    }

    // ==================== 状态变量 ====================
    protected float m_fCachedCurrentWeight = 0.0; // 缓存的当前重量（kg）
    protected float m_fCachedEncumbranceSpeedPenalty = 0.0; // 缓存的速度惩罚
    protected float m_fCachedBodyMassPercent = 0.0; // 缓存的有效负重占体重百分比
    protected float m_fCachedEncumbranceStaminaDrainMultiplier = 1.0; // 缓存的体力消耗倍数
    protected bool m_bEncumbranceCacheValid = false; // 缓存是否有效
    protected SCR_CharacterInventoryStorageComponent m_pCachedInventoryComponent; // 缓存的库存组件引用
    protected SCR_InventoryStorageManagerComponent m_pCachedInventoryManager; // 缓存的库存管理器组件（避免每 tick FindComponent）
    protected float m_fLastCheckTime = 0.0; // 上次检查时间（秒）
    protected const float ENCUMBRANCE_CHECK_INTERVAL = 0.2; // 轮询间隔（秒），结合事件驱动减少 GetTotalWeightOfAllStorages 调用

    // ==================== 公共方法 ====================

    // 初始化缓存
    // @param inventoryComponent 库存组件引用（可为null）
    void Initialize(SCR_CharacterInventoryStorageComponent inventoryComponent = null)
    {
        m_fCachedCurrentWeight = 0.0;
        m_fCachedEncumbranceSpeedPenalty = 0.0;
        m_fCachedBodyMassPercent = 0.0;
        m_fCachedEncumbranceStaminaDrainMultiplier = 1.0;
        m_bEncumbranceCacheValid = false;
        m_pCachedInventoryComponent = inventoryComponent;
        m_pCachedInventoryManager = null;

        // 如果提供了库存组件，初始化时计算一次负重
        if (m_pCachedInventoryComponent)
            UpdateCache();
    }

    // 设置库存组件引用
    // @param inventoryComponent 库存组件引用
    void SetInventoryComponent(SCR_CharacterInventoryStorageComponent inventoryComponent)
    {
        m_pCachedInventoryComponent = inventoryComponent;
        m_pCachedInventoryManager = null; // 重置，下次 UpdateCache 时重新查找
        if (m_pCachedInventoryComponent)
            UpdateCache();
        else
            m_bEncumbranceCacheValid = false;
    }

    // 更新缓存（事件驱动）
    // 仅在库存变化时调用，避免每0.2秒重复计算
    // 注意：需要在库存组件的事件中调用此方法（如 OnItemAdded/OnItemRemoved）
    void UpdateCache()
    {
        if (!m_pCachedInventoryComponent)
        {
            m_bEncumbranceCacheValid = false;
            return;
        }

        float currentWeight = 0.0;

        // 获取角色实体
        IEntity ownerEntity = m_pCachedInventoryComponent.GetOwner();
        if (!ownerEntity)
        {
            m_bEncumbranceCacheValid = false;
            return;
        }

        // 使用 SCR_InventoryStorageManagerComponent.GetTotalWeightOfAllStorages() 方法（唯一方式）
        if (!m_pCachedInventoryManager)
            m_pCachedInventoryManager = SCR_InventoryStorageManagerComponent.Cast(ownerEntity.FindComponent(SCR_InventoryStorageManagerComponent));
        if (m_pCachedInventoryManager)
        {
            // 使用官方推荐的 GetTotalWeightOfAllStorages() 方法，确保计算所有存储的重量
            currentWeight = m_pCachedInventoryManager.GetTotalWeightOfAllStorages();
        }
        else
        {
            // 如果无法获取 inventoryManager，设置缓存无效
            m_bEncumbranceCacheValid = false;
            if (StaminaConstants.IsDebugEnabled())
                Print("[RSS] UpdateCache - 无法获取 SCR_InventoryStorageManagerComponent");
            return;
        }

        if (currentWeight < 0.0)
        {
            m_bEncumbranceCacheValid = false;
            return;
        }

        // 更新缓存值
        m_fCachedCurrentWeight = currentWeight;

        // 计算有效负重（负载 = 载具/装备重量 - 基准装备重量）
        // GetTotalWeightOfAllStorages() 返回的是装备/背包重量，不含身体重量
        float effectiveWeight = Math.Max(currentWeight - StaminaConstants.BASE_WEIGHT, 0.0);
        m_fCachedBodyMassPercent = effectiveWeight / StaminaConstants.CHARACTER_WEIGHT;
        m_fCachedEncumbranceSpeedPenalty = ComputeSpeedPenaltyFromEffectiveWeight(effectiveWeight);

        // 计算体力消耗倍数
        float encumbranceStaminaDrainCoeff = StaminaConstants.GetEncumbranceStaminaDrainCoeff();
        m_fCachedEncumbranceStaminaDrainMultiplier = 1.0 + (encumbranceStaminaDrainCoeff * m_fCachedBodyMassPercent);
        m_fCachedEncumbranceStaminaDrainMultiplier = Math.Clamp(m_fCachedEncumbranceStaminaDrainMultiplier, 1.0, 3.0);

        m_bEncumbranceCacheValid = true;
    }

    // 检查并更新缓存（仅在变化时更新）
    // 在 UpdateSpeedBasedOnStamina 中调用，检查负重是否变化
    // 性能优化：按 ENCUMBRANCE_CHECK_INTERVAL 节流，减少 GetTotalWeightOfAllStorages 调用频率
    void CheckAndUpdate()
    {
        if (!m_pCachedInventoryComponent)
            return;

        float currentTime = GetGame().GetWorld().GetWorldTime() / 1000.0;
        if (m_bEncumbranceCacheValid && (currentTime - m_fLastCheckTime < ENCUMBRANCE_CHECK_INTERVAL))
            return;
        m_fLastCheckTime = currentTime;

        float currentWeight = 0.0;

        // 获取角色实体
        IEntity ownerEntity = m_pCachedInventoryComponent.GetOwner();
        if (ownerEntity)
        {
            if (!m_pCachedInventoryManager)
                m_pCachedInventoryManager = SCR_InventoryStorageManagerComponent.Cast(ownerEntity.FindComponent(SCR_InventoryStorageManagerComponent));
            if (m_pCachedInventoryManager)
            {
                currentWeight = m_pCachedInventoryManager.GetTotalWeightOfAllStorages();
            }
            else
            {
                // 回退方案：手动计算所有必要存储的重量
                array<BaseInventoryStorageComponent> storages = {};
                float weaponWeight = 0.0;
                float characterWeight = 0.0;

                // 按照官方 GetTotalWeightOfAllStorages() 方法的逻辑，手动添加必要的存储
                BaseInventoryStorageComponent weaponStorage = m_pCachedInventoryComponent.GetWeaponStorage();
                storages.Insert(weaponStorage); // 主副武器插槽
                storages.Insert(m_pCachedInventoryComponent);                    // 衣服、背包、背心里的东西

                // 遍历所有存储，累加重量
                foreach (BaseInventoryStorageComponent storage : storages)
                {
                    if (storage)
                    {
                        float storageWeight = storage.GetTotalWeight();
                        currentWeight += storageWeight;

                        if (storage == weaponStorage)
                            weaponWeight = storageWeight;
                        else if (storage == m_pCachedInventoryComponent)
                            characterWeight = storageWeight;
                    }
                }


            }
        }
        else
        {
            // 无角色实体时的回退方案
            float weaponWeight = 0.0;
            currentWeight = m_pCachedInventoryComponent.GetTotalWeight();

            // 添加武器存储重量
            BaseInventoryStorageComponent weaponStorage = m_pCachedInventoryComponent.GetWeaponStorage();
            if (weaponStorage)
            {
                weaponWeight = weaponStorage.GetTotalWeight();
                currentWeight += weaponWeight;
            }


        }

        // 如果重量变化超过0.1kg，重新计算缓存（避免微小浮点误差触发）
        if (Math.AbsFloat(currentWeight - m_fCachedCurrentWeight) > 0.1 || !m_bEncumbranceCacheValid)
        {
            UpdateCache();
        }
    }

    // ==================== 获取缓存值的方法 ====================

    // 获取缓存的当前重量
    // @return 当前重量（kg），如果缓存无效则返回0.0
    float GetCurrentWeight()
    {
        if (m_bEncumbranceCacheValid)
            return m_fCachedCurrentWeight;
        return 0.0;
    }

    // 获取缓存的速度惩罚
    // @return 速度惩罚值（0.0-0.5），如果缓存无效则返回0.0
    float GetSpeedPenalty()
    {
        if (m_bEncumbranceCacheValid)
            return m_fCachedEncumbranceSpeedPenalty;
        return 0.0;
    }

    // 获取缓存的有效负重占体重百分比
    // @return 有效负重占体重百分比（0.0-1.0+），如果缓存无效则返回0.0
    float GetBodyMassPercent()
    {
        if (m_bEncumbranceCacheValid)
            return m_fCachedBodyMassPercent;
        return 0.0;
    }

    // 获取缓存的体力消耗倍数
    // @return 体力消耗倍数（1.0-3.0），如果缓存无效则返回1.0
    float GetStaminaDrainMultiplier()
    {
        if (m_bEncumbranceCacheValid)
            return m_fCachedEncumbranceStaminaDrainMultiplier;
        return 1.0;
    }

    // 检查缓存是否有效
    // @return true表示缓存有效，false表示缓存无效
    bool IsCacheValid()
    {
        return m_bEncumbranceCacheValid;
    }

    // 获取库存组件引用
    // @return 库存组件引用（可为null）
    SCR_CharacterInventoryStorageComponent GetInventoryComponent()
    {
        return m_pCachedInventoryComponent;
    }
}

